//export nvmlDeviceGetRemappedRows
func nvmlDeviceGetRemappedRows(nvmlDevice unsafe.Pointer, corrRows unsafe.Pointer, uncRows unsafe.Pointer, isPending unsafe.Pointer, failureOccurred unsafe.Pointer) C.nvmlReturn_t {
	dev := engine.GetEngine().LookupDevice(uintptr(nvmlDevice))
	if dev == nil {
		return C.NVML_ERROR_INVALID_ARGUMENT
	}
	correctable, uncorrectable, pendingVal, failureVal, ret := dev.GetRemappedRows()
	if ret != nvml.SUCCESS {
		return toReturn(ret)
	}
	if corrRows != nil {
		*(*C.uint)(corrRows) = C.uint(correctable)
	}
	if uncRows != nil {
		*(*C.uint)(uncRows) = C.uint(uncorrectable)
	}
	if isPending != nil {
		if pendingVal {
			*(*C.uint)(isPending) = 1
		} else {
			*(*C.uint)(isPending) = 0
		}
	}
	if failureOccurred != nil {
		if failureVal {
			*(*C.uint)(failureOccurred) = 1
		} else {
			*(*C.uint)(failureOccurred) = 0
		}
	}
	return C.NVML_SUCCESS
}

