//export nvmlDeviceGetMigMode
func nvmlDeviceGetMigMode(nvmlDevice unsafe.Pointer, currentMode unsafe.Pointer, pendingMode unsafe.Pointer) C.nvmlReturn_t {
	dev := engine.GetEngine().LookupDevice(uintptr(nvmlDevice))
	if dev == nil {
		return C.NVML_ERROR_INVALID_ARGUMENT
	}
	curMode, pendMode, ret := dev.GetMigMode()
	if ret != nvml.SUCCESS {
		return toReturn(ret)
	}
	if currentMode != nil {
		*(*C.uint)(currentMode) = C.uint(curMode)
	}
	if pendingMode != nil {
		*(*C.uint)(pendingMode) = C.uint(pendMode)
	}
	return C.NVML_SUCCESS
}

